// Persistent immutable vector with structural sharing.
// Branching factor = 32 (2^5). All operations are O(log32 N) ≈ O(1).

const BITS = 5;                     // bits per tree level
const WIDTH = 1 << BITS;            // 32
const MASK = WIDTH - 1;             // 0b11111

type Node<T> = (Node<T> | T)[];     // internal tree node or leaf array

export class PersistentVector<T> {
    private readonly _size: number;
    private readonly _shift: number;   // total bits to reach leaf level
    private readonly _root: Node<T> | null;
    private readonly _tail: T[];

    private constructor(size: number, shift: number, root: Node<T> | null, tail: T[]) {
        this._size = size;
        this._shift = shift;
        this._root = root;
        this._tail = tail;
    }

    /** Empty vector */
    static empty<T>(): PersistentVector<T> {
        return new PersistentVector<T>(0, BITS, null, []);
    }

    /** Number of elements */
    get size(): number {
        return this._size;
    }

    /** Retrieve element at index (throws if out of range) */
    get(i: number): T {
        if (i < 0 || i >= this._size) {
            throw new RangeError('Index out of bounds');
        }
        const tailOffset = this._tailOffset();
        if (i >= tailOffset) {
            return this._tail[i & MASK];
        }
        let node = this._root as Node<T>;
        for (let level = this._shift; level > 0; level -= BITS) {
            node = node[(i >>> level) & MASK] as Node<T>;
        }
        return node[i & MASK] as T;
    }

    /** Return a new vector with value appended (original unchanged) */
    push(value: T): PersistentVector<T> {
        // fast path – tail not full
        if (this._tail.length < WIDTH) {
            const newTail = this._tail.concat(value);
            return new PersistentVector<T>(this._size + 1, this._shift, this._root, newTail);
        }

        // tail is full – need to push it into the tree
        const newRootInfo = this._pushTail(this._shift, this._root, this._tail);
        let newRoot = newRootInfo.root;
        let newShift = this._shift;

        // tree overflow? increase depth
        if ((this._size >>> BITS) > (1 << this._shift)) {
            newRoot = [this._root, this._newPath(this._shift, this._tail)];
            newShift += BITS;
        }

        // start a fresh tail with the new element
        return new PersistentVector<T>(this._size + 1, newShift, newRoot, [value]);
    }

    // ---------- internal helpers -----------------------------------------

    /** Offset where the current tail starts */
    private _tailOffset(): number {
        if (this._size < WIDTH) return 0;
        return ((this._size - 1) >>> BITS) << BITS;
    }

    /** Create a new path of internal nodes down to leaf */
    private _newPath(level: number, node: T[]): Node<T> {
        if (level === 0) return node as unknown as Node<T>;
        const next = this._newPath(level - BITS, node);
        return [next] as unknown as Node<T>;
    }

    /** Push a full tail into the tree, returning possibly new root */
    private _pushTail(level: number, parent: Node<T> | null, tailNode: T[]): { root: Node<T> } {
        const idx = ((this._size - 1) >>> level) & MASK;
        let newParent: Node<T>;

        if (parent) {
            // copy existing node for structural sharing
            newParent = parent.slice() as Node<T>;
        } else {
            // create a fresh node when climbing from null
            newParent = [] as unknown as Node<T>;
        }

        if (level === BITS) {
            // we are one level above leaves – insert the tail directly
            newParent[idx] = tailNode as unknown as Node<T>;
        } else {
            // descend recursively
            const child = (parent && parent[idx]) ? (parent[idx] as Node<T>) : null;
            const pushed = this._pushTail(level - BITS, child, tailNode);
            newParent[idx] = pushed.root;
        }

        return { root: newParent };

