// ParseQuery.ts
/** Parses a URL query string literal into an object type.
 *  Example:
 *    ParseQuery<"a=1">          // => { a: "1" }
 *    ParseQuery<"a=1&b=2">      // => { a: "1"; b: "2" }
 *    ParseQuery<"x=hi&y=lo&z=1"> // => { x: "hi"; y: "lo"; z: "1" }
 *    ParseQuery<"">             // => {}
 */
export type ParseQuery<S extends string> = _ParseQuery<S>;

type _ParseQuery<
  S extends string,
  Result extends Record<string, string> = {}
> =
  // empty input → finish recursion
  S extends ''
    ? Result
    : // split off the first pair (up to '&')
      S extends `${infer Pair}&${infer Rest}`
        ? _ParsePair<Pair, Rest, Result>
        : // no '&' left – the whole string is a single pair
          _ParsePair<S, '', Result>;

type _ParsePair<
  Pair extends string,
  Rest extends string,
  Acc extends Record<string, string>
> =
  // a well‑formed pair contains exactly one '='
  Pair extends `${infer Key}=${infer Value}`
    ? // add the key/value to the accumulator and continue with the rest
      _ParseQuery<Rest, Acc & { [K in Key]: Value }>
    : // malformed pair – ignore it and continue
      _ParseQuery<Rest, Acc>;

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  // Map each event name to an array of its handlers.
  private readonly listeners = new Map<keyof TEvents, Array<(...args: unknown[]) => void>>();

  /** Register a handler for the given event. */
  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.listeners.get(name) ?? [];
    // The handler conforms to the event's argument types, but we store it as a generic unknown‑args function.
    list.push(handler as (...args: unknown[]) => void);
    this.listeners.set(name, list);
  }

  /** Emit an event, invoking all registered handlers in order. */
  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const list = this.listeners.get(name);
    if (!list) return;

    // Each stored handler is actually of type (...args: TEvents[K]) => void,
    // so we assert that before calling.
    for (const h of list as Array<(...args: TEvents[K]) => void>) {
      h(...args);
    }
  }

  /** Optional: remove a specific handler. */
  off<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.listeners.get(name);
    if (!list) return;
    const idx = list.findIndex(h => h === (handler as (...args: unknown[]) => void));
    if (idx !== -1) list.splice(idx, 1);
    if (list.length === 0) this.listeners.delete(name);
  }

  /** Optional: remove all handlers for an event. */
  clear<K extends keyof TEvents>(name?: K): void {
    if (name !== undefined) {
      this.listeners.delete(name);
    } else {
      this.listeners.clear();
    }
  }
}

