class BinaryHeap {
    private data: number[] = [];
    /** comparator(a,b) < 0 => a has higher priority than b */
    constructor(private readonly compare: (a: number, b: number) => number) {}

    size(): number {
        return this.data.length;
    }

    peek(): number {
        if (this.size() === 0) {
            throw new Error('Heap is empty');
        }
        return this.data[0];
    }

    push(value: number): void {
        this.data.push(value);
        this.bubbleUp(this.size() - 1);
    }

    pop(): number {
        if (this.size() === 0) {
            throw new Error('Heap is empty');
        }
        const top = this.data[0];
        const last = this.data.pop()!;
        if (this.size() > 0) {
            this.data[0] = last;
            this.bubbleDown(0);
        }
        return top;
    }

    private parent(idx: number): number {
        return Math.floor((idx - 1) / 2);
    }
    private left(idx: number): number {
        return idx * 2 + 1;
    }
    private right(idx: number): number {
        return idx * 2 + 2;
    }

    private bubbleUp(idx: number): void {
        while (idx > 0) {
            const p = this.parent(idx);
            if (this.compare(this.data[idx], this.data[p]) < 0) {
                [this.data[idx], this.data[p]] = [this.data[p], this.data[idx]];
                idx = p;
            } else {
                break;
            }
        }
    }

    private bubbleDown(idx: number): void {
        const n = this.size();
        while (true) {
            const l = this.left(idx);
            const r = this.right(idx);
            let smallest = idx;

            if (l < n && this.compare(this.data[l], this.data[smallest]) < 0) {
                smallest = l;
            }
            if (r < n && this.compare(this.data[r], this.data[smallest]) < 0) {
                smallest = r;
            }
            if (smallest !== idx) {
                [this.data[idx], this.data[smallest]] = [this.data[smallest], this.data[idx]];
                idx = smallest;
            } else {
                break;
            }
        }
    }
}

